  1→import {
  2→  type ReactNode,
  3→  useCallback,
  4→  useEffect,
  5→  useMemo,
  6→  useRef,
  7→  useState,
  8→} from 'react';
  9→import './list.scss';
 10→import { ListContext } from './list_context';
 11→
 12→interface ListProps {
 13→  children: ReactNode;
 14→  itemCount: number;
 15→  onActiveIndexChange?: (index: number) => void;
 16→  onAction?: (index: number) => void;
 17→}
 18→
 19→export function List({
 20→  children,
 21→  itemCount,
 22→  onActiveIndexChange,
 23→  onAction,
 24→}: ListProps) {
 25→  const [activeIndex, setActiveIndexRaw] = useState(0);
 26→  const containerRef = useRef<HTMLDivElement>(null);
 27→
 28→  const setActiveIndex = useCallback(
 29→    (index: number) => {
 30→      setActiveIndexRaw(index);
 31→      onActiveIndexChange?.(index);
 32→    },
 33→    [onActiveIndexChange],
 34→  );
 35→
 36→  useEffect(() => {
 37→    if (itemCount === 0) {
 38→      setActiveIndex(0);
 39→    } else if (activeIndex >= itemCount) {
 40→      setActiveIndex(itemCount - 1);
 41→    }
 42→  }, [
 43→    itemCount,
 44→    activeIndex,
 45→    setActiveIndex,
 46→  ]);
 47→
 48→  useEffect(() => {
 49→    const container = containerRef.current;
 50→    if (!container) return;
 51→
 52→    const activeElement = container.querySelector<HTMLElement>(
 53→      `[data-list-index="${activeIndex}"]`,
 54→    );
 55→    activeElement?.scrollIntoView({ block: 'nearest' });
 56→  }, [activeIndex]);
 57→
 58→  useEffect(() => {
 59→    function handleKeyDown(e: KeyboardEvent) {
 60→      if (itemCount === 0) return;
 61→
 62→      if (e.ctrlKey && !e.metaKey && !e.altKey) {
 63→        if (e.key === 'n') {
 64→          e.preventDefault();
 65→          setActiveIndex(activeIndex < itemCount - 1 ? activeIndex + 1 : 0);
 66→          return;
 67→        }
 68→        if (e.key === 'p') {
 69→          e.preventDefault();
 70→          setActiveIndex(activeIndex > 0 ? activeIndex - 1 : itemCount - 1);
 71→          return;
 72→        }
 73→      }
 74→
 75→      if (e.metaKey || e.ctrlKey || e.altKey) return;
 76→
 77→      if (e.key === 'ArrowDown') {
 78→        e.preventDefault();
 79→        setActiveIndex(activeIndex < itemCount - 1 ? activeIndex + 1 : 0);
 80→      } else if (e.key === 'ArrowUp') {
 81→        e.preventDefault();
 82→        setActiveIndex(activeIndex > 0 ? activeIndex - 1 : itemCount - 1);
 83→      } else if (e.key === 'Enter') {
 84→        e.preventDefault();
 85→        onAction?.(activeIndex);
 86→      }
 87→    }
 88→
 89→    window.addEventListener('keydown', handleKeyDown);
 90→    return () => window.removeEventListener('keydown', handleKeyDown);
 91→  }, [
 92→    activeIndex,
 93→    itemCount,
 94→    setActiveIndex,
 95→    onAction,
 96→  ]);
 97→
 98→  const contextValue = useMemo(
 99→    () => ({
100→      activeIndex,
101→      setActiveIndex,
102→    }),
103→    [
104→      activeIndex,
105→      setActiveIndex,
106→    ],
107→  );
108→
109→  return (
110→    <ListContext value={contextValue}>
111→      <div ref={containerRef} className="list" role="listbox" id="command-list">
112→        {children}
113→      </div>
114→    </ListContext>
115→  );
116→}
