  1→import {
  2→  type ReactNode,
  3→  useCallback,
  4→  useEffect,
  5→  useMemo,
  6→  useRef,
  7→  useState,
  8→} from 'react';
  9→import './grid.scss';
 10→import { GridContext } from './grid_context';
 11→
 12→interface GridProps {
 13→  children: ReactNode;
 14→  itemCount: number;
 15→  columns?: 3 | 4 | 5 | 6;
 16→  onActiveIndexChange?: (index: number) => void;
 17→  onAction?: (index: number) => void;
 18→}
 19→
 20→export function Grid({
 21→  children,
 22→  itemCount,
 23→  columns = 4,
 24→  onActiveIndexChange,
 25→  onAction,
 26→}: GridProps) {
 27→  const [activeIndex, setActiveIndexRaw] = useState(0);
 28→  const containerRef = useRef<HTMLDivElement>(null);
 29→
 30→  const setActiveIndex = useCallback(
 31→    (index: number) => {
 32→      setActiveIndexRaw(index);
 33→      onActiveIndexChange?.(index);
 34→    },
 35→    [onActiveIndexChange],
 36→  );
 37→
 38→  useEffect(() => {
 39→    if (itemCount === 0) {
 40→      setActiveIndex(0);
 41→    } else if (activeIndex >= itemCount) {
 42→      setActiveIndex(itemCount - 1);
 43→    }
 44→  }, [
 45→    itemCount,
 46→    activeIndex,
 47→    setActiveIndex,
 48→  ]);
 49→
 50→  useEffect(() => {
 51→    const container = containerRef.current;
 52→    if (!container) return;
 53→
 54→    const activeElement = container.querySelector<HTMLElement>(
 55→      `[data-grid-index="${activeIndex}"]`,
 56→    );
 57→    activeElement?.scrollIntoView({ block: 'nearest' });
 58→  }, [activeIndex]);
 59→
 60→  useEffect(() => {
 61→    function handleKeyDown(e: KeyboardEvent) {
 62→      if (itemCount === 0) return;
 63→
 64→      if (e.ctrlKey && !e.metaKey && !e.altKey) {
 65→        const row = Math.floor(activeIndex / columns);
 66→        const col = activeIndex % columns;
 67→        const totalRows = Math.ceil(itemCount / columns);
 68→
 69→        if (e.key === 'n') {
 70→          e.preventDefault();
 71→          const nextRow = row + 1;
 72→          if (nextRow < totalRows) {
 73→            const nextIndex = nextRow * columns + col;
 74→            setActiveIndex(nextIndex < itemCount ? nextIndex : itemCount - 1);
 75→          } else {
 76→            setActiveIndex(col < itemCount ? col : 0);
 77→          }
 78→          return;
 79→        }
 80→        if (e.key === 'p') {
 81→          e.preventDefault();
 82→          const prevRow = row - 1;
 83→          if (prevRow >= 0) {
 84→            setActiveIndex(prevRow * columns + col);
 85→          } else {
 86→            const lastRowIndex = (totalRows - 1) * columns + col;
 87→            setActiveIndex(
 88→              lastRowIndex < itemCount ? lastRowIndex : itemCount - 1,
 89→            );
 90→          }
 91→          return;
 92→        }
 93→      }
 94→
 95→      if (e.metaKey || e.ctrlKey || e.altKey) return;
 96→
 97→      const isTextInput =
 98→        e.target instanceof HTMLInputElement ||
 99→        e.target instanceof HTMLTextAreaElement;
100→
101→      const row = Math.floor(activeIndex / columns);
102→      const col = activeIndex % columns;
103→      const totalRows = Math.ceil(itemCount / columns);
104→
105→      switch (e.key) {
106→        case 'ArrowRight': {
107→          if (isTextInput) return;
108→          e.preventDefault();
109→          const next = activeIndex + 1;
110→          setActiveIndex(next < itemCount ? next : 0);
111→          break;
112→        }
113→        case 'ArrowLeft': {
114→          if (isTextInput) return;
115→          e.preventDefault();
116→          const prev = activeIndex - 1;
117→          setActiveIndex(prev >= 0 ? prev : itemCount - 1);
118→          break;
119→        }
120→        case 'ArrowDown': {
121→          e.preventDefault();
122→          const nextRow = row + 1;
123→          if (nextRow < totalRows) {
124→            const nextIndex = nextRow * columns + col;
125→            setActiveIndex(nextIndex < itemCount ? nextIndex : itemCount - 1);
126→          } else {
127→            setActiveIndex(col < itemCount ? col : 0);
128→          }
129→          break;
130→        }
131→        case 'ArrowUp': {
132→          e.preventDefault();
133→          const prevRow = row - 1;
134→          if (prevRow >= 0) {
135→            setActiveIndex(prevRow * columns + col);
136→          } else {
137→            const lastRowIndex = (totalRows - 1) * columns + col;
138→            setActiveIndex(
139→              lastRowIndex < itemCount ? lastRowIndex : itemCount - 1,
140→            );
141→          }
142→          break;
143→        }
144→        case 'Enter': {
145→          e.preventDefault();
146→          onAction?.(activeIndex);
147→          break;
148→        }
149→      }
150→    }
151→
152→    window.addEventListener('keydown', handleKeyDown);
153→    return () => window.removeEventListener('keydown', handleKeyDown);
154→  }, [
155→    activeIndex,
156→    itemCount,
157→    columns,
158→    setActiveIndex,
159→    onAction,
160→  ]);
161→
162→  const contextValue = useMemo(
163→    () => ({
164→      activeIndex,
165→      setActiveIndex,
166→      columns,
167→    }),
168→    [
169→      activeIndex,
170→      setActiveIndex,
171→      columns,
172→    ],
173→  );
174→
175→  return (
176→    <GridContext value={contextValue}>
177→      <div
178→        ref={containerRef}
179→        className="grid"
180→        role="listbox"
181→        id="command-grid"
182→        style={{ '--grid-columns': columns } as React.CSSProperties}
183→      >
184→        {children}
185→      </div>
186→    </GridContext>
187→  );
188→}
