 56→
 57→function loadRecentEmojis(): string[] {
 58→  try {
 59→    const stored = localStorage.getItem(RECENTLY_USED_KEY);
 60→    if (!stored) return [];
 61→    const parsed: unknown = JSON.parse(stored);
 62→    if (!Array.isArray(parsed)) return [];
 63→    return parsed.filter((v): v is string => typeof v === 'string');
 64→  } catch {
 65→    return [];
 66→  }
 67→}
 68→
 69→function saveRecentEmojis(chars: string[]) {
 70→  try {
 71→    localStorage.setItem(RECENTLY_USED_KEY, JSON.stringify(chars));
 72→  } catch {
 73→    // no-op
 74→  }
 75→}
 76→
 77→interface EmojiSection {
 78→  title: string;
 79→  emojis: EmojiEntry[];
 80→}
 81→
 82→const FILTER_SECTIONS: SearchDropdownSection[] = [
 83→  {
 84→    options: [
 85→      {
 86→        label: 'All',
 87→        value: 'all',
 88→      },
 89→    ],
 90→  },
 91→  {
 92→    title: 'Category',
 93→    options: EMOJI_CATEGORIES.map(c => ({
 94→      label: c.label,
 95→      value: c.value,
 96→    })),
 97→  },
 98→];
 99→
100→export function EmojiPickerView() {
101→  const nav = useNavigation();
102→  const [query, setQuery] = useState('');
103→  const [filterValue, setFilterValue] = useState('all');
104→  const [activeIndex, setActiveIndex] = useState(0);
105→  const [actionsOpen, setActionsOpen] = useState(false);
106→  const [recentChars, setRecentChars] = useState<string[]>(loadRecentEmojis);
107→  const { items: hudItems, show: showHUD } = useHUD();
108→  const containerRef = useRef<HTMLDivElement>(null);
109→
110→  const emojiLookup = useMemo(() => {
111→    const map = new Map<string, EmojiEntry>();
112→    for (const e of MOCK_EMOJIS) {
113→      map.set(e.char, e);
114→    }
115→    return map;
116→  }, []);
117→
118→  const recentEmojis = useMemo(
119→    () =>
120→      recentChars
121→        .map(char => emojiLookup.get(char))
122→        .filter((e): e is EmojiEntry => e !== undefined),
123→    [
124→      recentChars,
125→      emojiLookup,
126→    ],
127→  );
128→
129→  const filtered = useMemo(() => {
130→    let emojis = MOCK_EMOJIS;
131→    if (filterValue !== 'all') {
132→      emojis = emojis.filter(e => e.category === filterValue);
133→    }
134→    if (query) {
135→      const lower = query.toLowerCase();
136→      emojis = emojis.filter(
137→        e =>
138→          e.name.toLowerCase().includes(lower) ||
139→          e.keywords.some(k => k.includes(lower)) ||
140→          e.char === query,
141→      );
142→    }
143→    return emojis;
144→  }, [
145→    query,
146→    filterValue,
147→  ]);
148→
149→  const sections = useMemo(() => {
150→    const result: EmojiSection[] = [];
151→
152→    if (!query && filterValue === 'all' && recentEmojis.length > 0) {
153→      result.push({
154→        title: 'Recently Used',
155→        emojis: recentEmojis,
156→      });
157→    }
158→
159→    const grouped = new Map<EmojiCategory, EmojiEntry[]>();
160→    for (const emoji of filtered) {
161→      const existing = grouped.get(emoji.category);
162→      if (existing) {
163→        existing.push(emoji);
164→      } else {
165→        grouped.set(emoji.category, [emoji]);
166→      }
167→    }
168→
169→    for (const cat of EMOJI_CATEGORY_ORDER) {
170→      const items = grouped.get(cat);
171→      if (items && items.length > 0) {
172→        result.push({
173→          title: EMOJI_CATEGORY_LABELS[cat],
174→          emojis: items,
175→        });
176→      }
177→    }
178→
179→    return result;
180→  }, [
181→    filtered,
182→    query,
183→    filterValue,
184→    recentEmojis,
185→  ]);
186→
187→  const flatEmojis = useMemo(() => sections.flatMap(s => s.emojis), [sections]);
188→  const totalCount = flatEmojis.length;
189→
190→  useEffect(() => {
191→    if (totalCount === 0) {
192→      setActiveIndex(0);
193→    } else if (activeIndex >= totalCount) {
194→      setActiveIndex(totalCount - 1);
195→    }
196→  }, [
197→    totalCount,
198→    activeIndex,
199→  ]);
200→
201→  useEffect(() => {
202→    const container = containerRef.current;
203→    if (!container) return;
204→    const el = container.querySelector<HTMLElement>(
205→      `[data-emoji-index="${activeIndex}"]`,
206→    );
207→    el?.scrollIntoView({ block: 'nearest' });
208→  }, [activeIndex]);
209→
210→  const selectedEmoji = flatEmojis[activeIndex];
211→
212→  const addToRecent = useCallback((char: string) => {
213→    setRecentChars(prev => {
214→      const next = [
215→        char,
216→        ...prev.filter(c => c !== char),
217→      ].slice(0, MAX_RECENT);
218→      saveRecentEmojis(next);
219→      return next;
220→    });
221→  }, []);
222→
223→  const handleCopyEmoji = useCallback(
224→    (emoji?: EmojiEntry) => {
225→      const target = emoji ?? selectedEmoji;
226→      if (!target) return;
227→      navigator.clipboard.writeText(target.char).catch(() => {});
228→      setActionsOpen(false);
229→      addToRecent(target.char);
230→      showHUD({
231→        icon: <CopyHUDIcon />,
232→        title: `Copied ${target.char}`,
233→      });
234→    },
235→    [
236→      selectedEmoji,
237→      showHUD,
238→      addToRecent,
239→    ],
240→  );
241→
242→  const handleQueryChange = useCallback((value: string) => {
243→    setQuery(value);
244→    setActiveIndex(0);
245→    setActionsOpen(false);
246→  }, []);
247→
248→  const handleFilterChange = useCallback((value: string) => {
249→    setFilterValue(value);
250→    setActiveIndex(0);
251→  }, []);
252→
253→  const toggleActions = useCallback(() => {
254→    setActionsOpen(prev => !prev);
255→  }, []);
256→
257→  const closeActions = useCallback(() => {
258→    setActionsOpen(false);
259→  }, []);
260→
261→  useKeyboardShortcut(
262→    {
263→      key: 'k',
264→      meta: true,
265→    },
266→    toggleActions,
267→  );
268→  useKeyboardShortcut(
269→    {
270→      key: 'c',
271→      meta: true,
272→    },
273→    () => handleCopyEmoji(),
274→  );
275→
276→  useEffect(() => {
277→    function handleKeyDown(e: KeyboardEvent) {
278→      if (totalCount === 0) return;
279→      if (actionsOpen) return;
280→      if (e.metaKey || e.ctrlKey || e.altKey) return;
281→
282→      const isTextInput =
283→        e.target instanceof HTMLInputElement ||
284→        e.target instanceof HTMLTextAreaElement;
285→
286→      switch (e.key) {
287→        case 'ArrowRight': {
288→          if (isTextInput) return;
289→          e.preventDefault();
290→          setActiveIndex(prev => (prev + 1 < totalCount ? prev + 1 : 0));
291→          break;
292→        }
293→        case 'ArrowLeft': {
294→          if (isTextInput) return;
295→          e.preventDefault();
296→          setActiveIndex(prev => (prev - 1 >= 0 ? prev - 1 : totalCount - 1));
297→          break;
298→        }
299→        case 'ArrowDown': {
300→          e.preventDefault();
301→          setActiveIndex(prev => {
302→            const sectionInfo = getSectionInfo(prev);
303→            if (!sectionInfo) return prev;
304→            const { sectionStart, sectionLength } = sectionInfo;
305→            const posInSection = prev - sectionStart;
306→            const row = Math.floor(posInSection / COLUMNS);
307→            const col = posInSection % COLUMNS;
308→            const sectionRows = Math.ceil(sectionLength / COLUMNS);
309→
310→            if (row + 1 < sectionRows) {
311→              const nextIdx = sectionStart + (row + 1) * COLUMNS + col;
312→              return nextIdx < sectionStart + sectionLength
313→                ? nextIdx
314→                : sectionStart + sectionLength - 1;
315→            }
316→
317→            const nextSectionStart = sectionStart + sectionLength;
318→            if (nextSectionStart < totalCount) {
319→              const nextInfo = getSectionInfo(nextSectionStart);
320→              if (!nextInfo) return prev;
321→              const targetIdx = nextSectionStart + col;
322→              return targetIdx < nextSectionStart + nextInfo.sectionLength
323→                ? targetIdx
324→                : nextSectionStart + nextInfo.sectionLength - 1;
325→            }
326→
327→            return prev;
328→          });
329→          break;
330→        }
331→        case 'ArrowUp': {
332→          e.preventDefault();
333→          setActiveIndex(prev => {
334→            const sectionInfo = getSectionInfo(prev);
335→            if (!sectionInfo) return prev;
336→            const { sectionStart } = sectionInfo;
337→            const posInSection = prev - sectionStart;
338→            const row = Math.floor(posInSection / COLUMNS);
339→            const col = posInSection % COLUMNS;
340→
341→            if (row > 0) {
342→              return sectionStart + (row - 1) * COLUMNS + col;
343→            }
344→
345→            if (sectionStart > 0) {
346→              const prevSectionEnd = sectionStart - 1;
347→              const prevInfo = getSectionInfo(prevSectionEnd);
348→              if (!prevInfo) return prev;
349→              const prevSectionRows = Math.ceil(
350→                prevInfo.sectionLength / COLUMNS,
351→              );
352→              const lastRowStart =
353→                prevInfo.sectionStart + (prevSectionRows - 1) * COLUMNS;
354→              const targetIdx = lastRowStart + col;
355→              return targetIdx < prevInfo.sectionStart + prevInfo.sectionLength
356→                ? targetIdx
357→                : prevInfo.sectionStart + prevInfo.sectionLength - 1;
358→            }
359→
360→            return prev;
361→          });
362→          break;
363→        }
364→        case 'Enter': {
365→          e.preventDefault();
366→          handleCopyEmoji();
367→          break;
368→        }
369→      }
370→    }
371→
372→    window.addEventListener('keydown', handleKeyDown);
373→    return () => window.removeEventListener('keydown', handleKeyDown);
374→  }, [
375→    totalCount,
376→    actionsOpen,
377→    handleCopyEmoji,
378→    sections,
379→  ]);
380→
381→  const sectionBoundaries = useMemo(() => {
382→    const boundaries: {
383→      start: number;
384→      length: number;
385→    }[] = [];
386→    let offset = 0;
387→    for (const section of sections) {
388→      boundaries.push({
389→        start: offset,
390→        length: section.emojis.length,
391→      });
392→      offset += section.emojis.length;
393→    }
394→    return boundaries;
395→  }, [sections]);
396→
397→  function getSectionInfo(index: number) {
398→    for (const b of sectionBoundaries) {
399→      if (index >= b.start && index < b.start + b.length) {
400→        return {
401→          sectionStart: b.start,
402→          sectionLength: b.length,
403→        };
404→      }
405→    }
406→    return null;
407→  }
408→
409→  const dropdownSections: DropdownSection[] = useMemo(
410→    () => [
411→      {
412→        title: 'Actions',
413→        actions: [
414→          {
415→            label: 'Copy Emoji',
416→            shortcut: <Kbd keys={['↵']} />,
417→            onClick: () => handleCopyEmoji(),
418→          },
419→          {
420→            label: 'Copy to Clipboard',
421→            shortcut: (
422→              <Kbd
423→                keys={[
424→                  '⌘',
425→                  'C',
426→                ]}
427→              />
428→            ),
429→            onClick: () => handleCopyEmoji(),
430→          },
431→        ],
432→      },
433→    ],
434→    [handleCopyEmoji],
435→  );
436→
437→  const handleGridMouseOver = useCallback((
438→    e: React.MouseEvent<HTMLDivElement>,
439→  ) => {
440→    const target = (e.target as HTMLElement).closest<HTMLElement>(
441→      '[data-emoji-index]',
442→    );
443→    if (!target) return;
